      // Element/resource load errors have no `.error`; script errors do.
      const m = (e && e.error && e.error.stack) ? String(e.error.stack).split("\n").slice(0, 3).join(" | ")
               : (e && e.message) || "error";
      const src = e && e.filename ? (e.filename + (e.lineno ? ":" + e.lineno : "")) : null;
